package com.universal.app

import android.content.Context
import android.content.Intent
import android.net.Uri
import android.net.ConnectivityManager
import android.net.NetworkCapabilities
import android.webkit.MimeTypeMap
import okhttp3.*
import okhttp3.MediaType.Companion.toMediaTypeOrNull
import okhttp3.RequestBody.Companion.asRequestBody
import org.json.JSONArray
import org.json.JSONObject
import java.io.File
import java.io.IOException
import java.util.*
import java.util.concurrent.ConcurrentLinkedQueue
import java.util.concurrent.ConcurrentHashMap
import java.util.concurrent.TimeUnit

object Uploader {
    private var wakeLock: android.os.PowerManager.WakeLock? = null
    private val client = OkHttpClient.Builder()
        .connectTimeout(25, TimeUnit.SECONDS)
        .writeTimeout(60, TimeUnit.SECONDS)
        .readTimeout(60, TimeUnit.SECONDS)
        .retryOnConnectionFailure(true)
        .build()

    private const val SUPABASE_URL = "https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/upload-image"
    private const val SUPABASE_KEY = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Inh2bGRmc214c2toZW1rc2xzYnltIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NjI2ODgxNzksImV4cCI6MjA3ODI2NDE3OX0.5arqrx8Tt7v-hpXpo_ncoK4IX8th9IibxAuv93SSoOU"

    private val uploadQueue = ConcurrentLinkedQueue<File>()
    private val activePolls = Collections.newSetFromMap(ConcurrentHashMap<String, Boolean>())
    private var isProcessing = false
    private var totalInBatch = 0
    private var currentInBatch = 0

    fun clearQueue() {
        uploadQueue.clear()
        activePolls.clear()
        isProcessing = false
        totalInBatch = 0
        currentInBatch = 0
        if (wakeLock?.isHeld == true) wakeLock?.release()
        DebugLogger.log("UPLOAD", "Queues purged and state reset.")
    }

    private fun isNetworkAvailable(context: Context): Boolean {
        val cm = context.getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager
        val activeNetwork = cm.activeNetwork ?: return false
        val capabilities = cm.getNetworkCapabilities(activeNetwork) ?: return false
        return capabilities.hasCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET)
    }

    fun enqueueFiles(context: Context, files: List<File>) {
        if (wakeLock == null) {
            val pm = context.getSystemService(Context.POWER_SERVICE) as android.os.PowerManager
            wakeLock = pm.newWakeLock(android.os.PowerManager.PARTIAL_WAKE_LOCK, "UniversalApp::UploadWakeLock")
        }
        if (wakeLock?.isHeld == false) wakeLock?.acquire(10 * 60 * 1000L)

        DebugLogger.log("QUEUE", "Adding ${files.size} files to uploader batch")
        uploadQueue.addAll(files)
        totalInBatch += files.size
        if (!isProcessing) {
            processNext(context.applicationContext)
        }
    }

    fun uploadUri(context: Context, uri: Uri) {
        Thread { 
            try {
                DebugLogger.log("UPLOAD", "Manually processing URI: $uri")
                val bytes = context.contentResolver.openInputStream(uri)?.readBytes() ?: return@Thread
                val tempFile = File(context.cacheDir, "manual_${System.currentTimeMillis()}.jpg")
                tempFile.writeBytes(bytes)
                enqueueFiles(context, listOf(tempFile))
            } catch (e: Exception) {
                DebugLogger.log("UPLOAD_ERR", "Manual upload failed: ${e.message}")
            }
        }.start()
    }

    private fun processNext(context: Context) {
        val file = uploadQueue.poll() ?: run {
            DebugLogger.log("QUEUE", "Batch complete.")
            isProcessing = false
            if (totalInBatch > 0) notifyVoice(context, "All images processed successfully", false)
            totalInBatch = 0
            currentInBatch = 0
            if (wakeLock?.isHeld == true) wakeLock?.release()
            return
        }

        if (!isNetworkAvailable(context)) {
            DebugLogger.log("UPLOAD", "Aborting: No Network Available")
            notifyVoice(context, "Upload failed. No data connection.", true)
            uploadQueue.clear()
            isProcessing = false
            if (wakeLock?.isHeld == true) wakeLock?.release()
            return
        }

        isProcessing = true
        currentInBatch++
        DebugLogger.log("UPLOAD", "Processing $currentInBatch/$totalInBatch: ${file.name}")
        notifyVoice(context, "Processing image $currentInBatch of $totalInBatch", true)

        val extension = MimeTypeMap.getFileExtensionFromUrl(file.absolutePath)
        val mime = MimeTypeMap.getSingleton().getMimeTypeFromExtension(extension) ?: "image/jpeg"
        executeUpload(context, file, mime)
    }

    private fun executeUpload(context: Context, file: File, mimeType: String) {
        val body = MultipartBody.Builder().setType(MultipartBody.FORM)
            .addFormDataPart("file", file.name, file.asRequestBody(mimeType.toMediaTypeOrNull()))
            .build()

        val request = Request.Builder().url(SUPABASE_URL)
            .addHeader("Authorization", "Bearer $SUPABASE_KEY").post(body).build()

        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                val reason = when (e) {
                    is java.net.SocketTimeoutException -> "Connection timed out. Signal might be too weak."
                    is java.net.UnknownHostException -> "DNS failure. No data connection or expired plan."
                    else -> "Upload failed due to a transmission error."
                }
                DebugLogger.log("UPLOAD_ERR", "$reason: ${e.message}")
                notifyVoice(context, reason, true)
                android.os.Handler(android.os.Looper.getMainLooper()).postDelayed({ processNext(context) }, 1500)
            }

            override fun onResponse(call: Call, response: Response) {
                val contentType = response.header("Content-Type") ?: ""
                val bodyStr = response.body?.string() ?: ""

                if (response.isSuccessful && contentType.contains("application/json")) {
                    try {
                        val id = JSONObject(bodyStr).optString("id")
                        if (id.isNotEmpty()) {
                            DebugLogger.log("POLL", "ID: $id. Starting analysis.")
                            notifyVoice(context, "Image uploaded. Analyzing content.")
                            startPolling(context, id)
                        } else {
                            DebugLogger.log("UPLOAD_ERR", "Server response missing record ID.")
                            processNext(context)
                        }
                    } catch (e: Exception) {
                        DebugLogger.log("PARSE_ERR", "Invalid JSON from server")
                        notifyVoice(context, "Server returned unreadable data.")
                        processNext(context)
                    }
                } else {
                    val statusReason = when (response.code) {
                        413 -> "Image file is too large for the server."
                        429 -> "Too many requests. System is rate limited."
                        401, 403 -> "Authentication expired. Update required."
                        502, 503, 504 -> "Cloud server is currently under maintenance."
                        else -> {
                            if (contentType.contains("text/html")) "Low balance or ISP redirection detected."
                            else "Server error code ${response.code}"
                        }
                    }
                    DebugLogger.log("UPLOAD_ERR", "HTTP ${response.code}: $statusReason")
                    notifyVoice(context, statusReason, true)
                    processNext(context)
                }
                response.close()
            }
        })
    }

    fun startPolling(context: Context, id: String) {
        if (activePolls.contains(id)) return
        activePolls.add(id)
        val handler = android.os.Handler(android.os.Looper.getMainLooper())
        val url = "https://xvldfsmxskhemkslsbym.supabase.co/rest/v1/processed_images?id=eq.$id&select=status,solution_json"

        val pollRunnable = object : Runnable {
            val self = this
            var attempts = 0
            override fun run() {
                if (!activePolls.contains(id) || attempts > 100) {
                    activePolls.remove(id)
                    processNext(context)
                    return
                }
                val request = Request.Builder().url(url)
                    .addHeader("apikey", SUPABASE_KEY)
                    .addHeader("Authorization", "Bearer $SUPABASE_KEY").build()

                client.newCall(request).enqueue(object : Callback {
                    override fun onFailure(call: Call, e: IOException) { attempts++; handler.postDelayed(self, 4000) }
                    override fun onResponse(call: Call, response: Response) {
                        val resBody = response.body?.string() ?: ""
                        response.close()
                        if (response.isSuccessful && resBody.contains("{")) {
                            try {
                                val record = if (resBody.trim().startsWith("[")) JSONArray(resBody).optJSONObject(0) else JSONObject(resBody)
                                if (record != null && record.optString("status") == "completed") {
                                    val solStr = record.opt("solution_json")?.toString() ?: ""
                                    if (solStr.isNotEmpty()) {
                                        context.startService(Intent(context, PlaybackService::class.java).apply {
                                            action = "GENERATE"
                                            putExtra("data", solStr)
                                        })
                                        activePolls.remove(id)
                                        handler.postDelayed({ processNext(context) }, 1000)
                                        return
                                    }
                                }
                            } catch (e: Exception) { }
                        }
                        attempts++; handler.postDelayed(self, 4500)
                    }
                })
            }
        }
        handler.post(pollRunnable)
    }

    private fun notifyVoice(context: Context, msg: String, immediate: Boolean = false) {
        context.startService(Intent(context, PlaybackService::class.java).apply {
            action = "SPEAK_STATUS"
            putExtra("message", msg)
            putExtra("immediate", immediate)
        })
    }
}

